const { Storage } = require('@google-cloud/storage');
const path = require('path');

const storage = new Storage();

const ALLOWED_BUCKETS = process.env.ALLOWED_BUCKETS ? process.env.ALLOWED_BUCKETS.split(',') : [];
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '104857600', 10);
const ALLOWED_EXTENSIONS = process.env.ALLOWED_EXTENSIONS ? 
  process.env.ALLOWED_EXTENSIONS.split(',') : 
  ['.jpg', '.jpeg', '.png', '.gif', '.pdf', '.txt', '.json', '.xml', '.csv', '.zip', '.mp4', '.mp3', '.doc', '.docx'];

const CONTENT_TYPE_MAP = {
  '.jpg': 'image/jpeg',
  '.jpeg': 'image/jpeg',
  '.png': 'image/png',
  '.gif': 'image/gif',
  '.pdf': 'application/pdf',
  '.txt': 'text/plain',
  '.json': 'application/json',
  '.xml': 'application/xml',
  '.csv': 'text/csv',
  '.zip': 'application/zip',
  '.mp4': 'video/mp4',
  '.mp3': 'audio/mpeg',
  '.doc': 'application/msword',
  '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  '.html': 'text/html',
  '.css': 'text/css',
  '.js': 'application/javascript'
};

function sanitizePath(filePath) {
  if (!filePath || typeof filePath !== 'string') {
    return null;
  }

  const normalized = path.normalize(filePath).replace(/^(\.\.(\/|\\|$))+/, '');
  
  if (normalized.includes('..') || normalized.startsWith('/') || normalized.startsWith('\\')) {
    return null;
  }

  if (normalized.match(/[<>:"|?*\x00-\x1f]/)) {
    return null;
  }

  return normalized.replace(/\\/g, '/');
}

function validateBucket(bucketName) {
  if (!bucketName || typeof bucketName !== 'string') {
    return false;
  }

  if (ALLOWED_BUCKETS.length > 0 && !ALLOWED_BUCKETS.includes(bucketName)) {
    return false;
  }

  if (!bucketName.match(/^[a-z0-9][a-z0-9._-]{1,61}[a-z0-9]$/)) {
    return false;
  }

  return true;
}

function validateFileExtension(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  return ALLOWED_EXTENSIONS.includes(ext);
}

function getContentType(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  return CONTENT_TYPE_MAP[ext] || 'application/octet-stream';
}

async function validateFileSize(file) {
  try {
    const [metadata] = await file.getMetadata();
    const fileSize = parseInt(metadata.size, 10);
    
    if (fileSize > MAX_FILE_SIZE) {
      return false;
    }
    
    return true;
  } catch (error) {
    return false;
  }
}

exports.serveFile = async (req, res) => {
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('X-XSS-Protection', '1; mode=block');
  res.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');

  if (req.method !== 'GET' && req.method !== 'HEAD') {
    res.status(405).send({ error: 'Method not allowed' });
    return;
  }

  const bucketName = req.query.bucket;
  const filePath = req.query.path || req.query.file;

  if (!bucketName) {
    res.status(400).send({ error: 'Bucket name is required' });
    return;
  }

  if (!filePath) {
    res.status(400).send({ error: 'File path is required' });
    return;
  }

  if (!validateBucket(bucketName)) {
    res.status(403).send({ error: 'Invalid or unauthorized bucket' });
    return;
  }

  const sanitizedPath = sanitizePath(filePath);
  if (!sanitizedPath) {
    res.status(400).send({ error: 'Invalid file path' });
    return;
  }

  if (!validateFileExtension(sanitizedPath)) {
    res.status(403).send({ error: 'File type not allowed' });
    return;
  }

  try {
    const bucket = storage.bucket(bucketName);
    const file = bucket.file(sanitizedPath);

    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send({ error: 'File not found' });
      return;
    }

    const isValidSize = await validateFileSize(file);
    if (!isValidSize) {
      res.status(413).send({ error: 'File size exceeds maximum allowed size' });
      return;
    }

    const [metadata] = await file.getMetadata();
    
    const contentType = metadata.contentType || getContentType(sanitizedPath);
    res.set('Content-Type', contentType);
    res.set('Content-Length', metadata.size);
    res.set('Cache-Control', 'public, max-age=3600');
    res.set('ETag', metadata.etag);
    
    const fileName = path.basename(sanitizedPath);
    res.set('Content-Disposition', `inline; filename="${fileName}"`);

    if (req.method === 'HEAD') {
      res.status(200).end();
      return;
    }

    const readStream = file.createReadStream();

    readStream.on('error', (error) => {
      console.error('Stream error:', error);
      if (!res.headersSent) {
        res.status(500).send({ error: 'Error streaming file' });
      } else {
        res.end();
      }
    });

    readStream.pipe(res);

  } catch (error) {
    console.error('Error serving file:', error);
    
    if (!res.headersSent) {
      if (error.code === 403) {
        res.status(403).send({ error: 'Access denied' });
      } else if (error.code === 404) {
        res.status(404).send({ error: 'File not found' });
      } else {
        res.status(500).send({ error: 'Internal server error' });
      }
    }
  }
};